create table if not exists public.profiles (id uuid references auth.users(id) on delete cascade primary key, email text, full_name text, avatar_url text, plan text default 'free' check (plan in ('free', 'pro', 'business')), stripe_customer_id text, created_at timestamptz default now(), updated_at timestamptz default now());
create table if not exists public.teams (id uuid default uuid_generate_v4() primary key, name text not null, owner_id uuid references public.profiles(id) on delete cascade not null, plan text default 'free' check (plan in ('free', 'pro', 'business')), stripe_customer_id text, stripe_subscription_id text, created_at timestamptz default now(), updated_at timestamptz default now());
create table if not exists public.team_members (team_id uuid references public.teams(id) on delete cascade, user_id uuid references public.profiles(id) on delete cascade, role text default 'member' check (role in ('owner', 'admin', 'member')), created_at timestamptz default now(), primary key (team_id, user_id));
create table if not exists public.projects (id uuid default uuid_generate_v4() primary key, team_id uuid references public.teams(id) on delete cascade, name text not null, description text, topology_yaml text, created_at timestamptz default now(), updated_at timestamptz default now());
create table if not exists public.simulation_runs (id uuid default uuid_generate_v4() primary key, project_id uuid references public.projects(id) on delete cascade, team_id uuid references public.teams(id) on delete cascade, user_id uuid references public.profiles(id), overall_score numeric(5,2), availability_estimate text, nines numeric(5,2), engine_type text default 'static', scenarios_passed integer default 0, scenarios_failed integer default 0, total_scenarios integer default 0, result_data jsonb, created_at timestamptz default now());
create table if not exists public.billing_events (id uuid default uuid_generate_v4() primary key, team_id uuid references public.teams(id) on delete cascade, event_type text not null, stripe_event_id text, data jsonb, created_at timestamptz default now());
create table if not exists public.usage (id uuid default uuid_generate_v4() primary key, team_id uuid references public.teams(id) on delete cascade, month text not null, simulation_count integer default 0, created_at timestamptz default now(), unique(team_id, month));
